#!/usr/bin/env bash
# SUDO_COMMANDS_R3.sh
# Generated by Phases 13-19 mega run. Run manually after the autonomous run.
# Each block is annotated with the phase + task that needs it.
set -euo pipefail
echo "Nexus mega-run sudo commands (phases 13-19)."
echo "Review each section before running."

# ---------------------------------------------------------------------------
# Phase 13.1 — install nexus-prewarm.service (oneshot after nexus-api)
# ---------------------------------------------------------------------------
sudo cp /tmp/nexus-prewarm.service /etc/systemd/system/nexus-prewarm.service
sudo systemctl daemon-reload
sudo systemctl enable nexus-prewarm.service
# Run it once now so router/heavy are warm without a reboot:
sudo systemctl start nexus-prewarm.service

# ---------------------------------------------------------------------------
# Phase 13.9 — restart nexus-api so the long-running service picks up the new
# Phase 13 code (streaming CLI, fast_mode, parallel tools, truncation,
# instant ack, prompt-cache prefix).
# ---------------------------------------------------------------------------
sudo systemctl restart nexus-api.service
# Tail logs briefly to confirm startup is clean:
journalctl -u nexus-api.service -n 30 --no-pager

# ---------------------------------------------------------------------------
# Phase 14.4 — install the weekly LESSONS.md aggregator (Mondays 8am).
# ---------------------------------------------------------------------------
sudo cp /tmp/nexus-lessons.service /etc/systemd/system/nexus-lessons.service
sudo cp /tmp/nexus-lessons.timer /etc/systemd/system/nexus-lessons.timer
sudo systemctl daemon-reload
sudo systemctl enable --now nexus-lessons.timer
# Verify next firing:
systemctl list-timers nexus-lessons.timer --no-pager

# ---------------------------------------------------------------------------
# Phase 14.5 — install the nightly regression-test timer (3am).
# ---------------------------------------------------------------------------
sudo cp /tmp/nexus-test.service /etc/systemd/system/nexus-test.service
sudo cp /tmp/nexus-test.timer /etc/systemd/system/nexus-test.timer
sudo systemctl daemon-reload
sudo systemctl enable --now nexus-test.timer
systemctl list-timers nexus-test.timer --no-pager

# ---------------------------------------------------------------------------
# Phase 15.3 — install the Nexus task worker (Restart=always background loop).
# Pull the API restart line ABOVE this block first so the worker links against
# the new code.
# ---------------------------------------------------------------------------
sudo cp /tmp/nexus-task-worker.service /etc/systemd/system/nexus-task-worker.service
sudo systemctl daemon-reload
sudo systemctl enable --now nexus-task-worker.service
sudo systemctl status nexus-task-worker.service --no-pager

# ---------------------------------------------------------------------------
# Phase 15.7 — Telegram bot back on. Run ONLY after Phase 15 verification
# (PHASE_15_VERIFY.md) shows PASS and the worker is up.
# Reload the listener code first so it picks up the conversation_handler
# routing and the fast-path intent classifier added in 15.4 / 15.5.
# ---------------------------------------------------------------------------
sudo systemctl daemon-reload
sudo systemctl enable nexus-telegram.service
sudo systemctl restart nexus-telegram.service
journalctl -u nexus-telegram.service -n 30 --no-pager

# ---------------------------------------------------------------------------
# Phase 16.2 — optional: pull a vision-language model so
# find_on_screen_vision works without the "model not installed" fallback.
# Disk: ~6 GB. No sudo required, but listed here so it's part of the same
# checklist Colton runs after the autonomous batch.
# ---------------------------------------------------------------------------
ollama pull qwen2.5vl:7b
ollama list | grep -i vl

# ---------------------------------------------------------------------------
# Phase 16.5 — install the standalone scheduler tick loop.
# ---------------------------------------------------------------------------
sudo cp /tmp/nexus-scheduler.service /etc/systemd/system/nexus-scheduler.service
sudo systemctl daemon-reload
sudo systemctl enable --now nexus-scheduler.service
systemctl status nexus-scheduler.service --no-pager

# ---------------------------------------------------------------------------
# Phase 16.6 — wake word listener.
# (1) install deps in the Nexus venv. NO sudo needed for pip:
~/AI_Agent/venv/bin/pip install openwakeword sounddevice numpy
~/AI_Agent/venv/bin/python3 -c "import openwakeword; openwakeword.utils.download_models()"
# (2) optional: train a custom 'hey_nexus' model and replace WAKE_MODELS in
# workers/wakeword_listener.py — see docs/wakeword-setup.md (TBD).
# (3) install the service:
sudo cp /tmp/nexus-wakeword.service /etc/systemd/system/nexus-wakeword.service
sudo systemctl daemon-reload
sudo systemctl enable --now nexus-wakeword.service
journalctl -u nexus-wakeword.service -n 20 --no-pager

# ---------------------------------------------------------------------------
# Phase 16.7 — performance guardian. 60s tick, hysteresis 30 min.
# ---------------------------------------------------------------------------
~/AI_Agent/venv/bin/pip install psutil  # falls back to /proc if missing
sudo cp /tmp/nexus-perf-guardian.service /etc/systemd/system/nexus-perf-guardian.service
sudo systemctl daemon-reload
sudo systemctl enable --now nexus-perf-guardian.service
journalctl -u nexus-perf-guardian.service -n 20 --no-pager

# ---------------------------------------------------------------------------
# Phase 17 — minimal-viable observability dashboard at port 11438.
# ---------------------------------------------------------------------------
sudo cp /tmp/nexus-dashboard.service /etc/systemd/system/nexus-dashboard.service
sudo systemctl daemon-reload
sudo systemctl enable --now nexus-dashboard.service
echo "open http://localhost:11438/ (or http://100.124.210.84:11438/ via Tailscale)"

# ---------------------------------------------------------------------------
# Phase 18.5 — install the weekly Ollama model watcher (Mon 09:00).
# ---------------------------------------------------------------------------
sudo cp /tmp/nexus-model-watcher.service /etc/systemd/system/nexus-model-watcher.service
sudo cp /tmp/nexus-model-watcher.timer /etc/systemd/system/nexus-model-watcher.timer
sudo systemctl daemon-reload
sudo systemctl enable --now nexus-model-watcher.timer
systemctl list-timers nexus-model-watcher.timer --no-pager


